import{_ as e,o as a,c as n,e as s}from"./app.8bbedbe7.js";const r={},c=s(`<h1 id="docker安装portainer" tabindex="-1"><a class="header-anchor" href="#docker安装portainer" aria-hidden="true">#</a> docker安装portainer</h1><p><code>portainer</code>是管理docker容器和镜像的可视化工具</p><h2 id="安装运行" tabindex="-1"><a class="header-anchor" href="#安装运行" aria-hidden="true">#</a> 安装运行</h2><p>目前docker中的<code>portainer</code>包含CE（Community Edition，社区版）和EE（Enterprise Edition，企业版）两个版本，我们拉取免费的CE版即可</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> pull portainer/portainer-ce
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>运行容器</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">--name</span><span class="token operator">=</span>portainer <span class="token punctuation">\\</span>
    <span class="token parameter variable">-p</span> <span class="token number">8000</span>:8000 <span class="token parameter variable">-p</span> <span class="token number">9000</span>:9000 <span class="token punctuation">\\</span>
    <span class="token parameter variable">--restart</span><span class="token operator">=</span>always <span class="token punctuation">\\</span>
    <span class="token parameter variable">-v</span> /var/run/docker.sock:/var/run/docker.sock <span class="token punctuation">\\</span>
    portainer/portainer-ce
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后访问<code>http://宿主机ip:9000</code>地址就可以打开portainer管理界面，首次登录需要设置登录密码</p><p>登录成功后系统默认为我们推荐了<code>local</code>环境，只需要点击进入即可管理本机docker</p><h2 id="连接管理" tabindex="-1"><a class="header-anchor" href="#连接管理" aria-hidden="true">#</a> 连接管理</h2><p>如果只需要管理本机docker，可以直接选择<code>local</code>即可</p><p>如果还需要管理远程主机docker，那么首先需要开启<strong>远程主机docker的2375端口</strong></p><h3 id="开启docker远程端口" tabindex="-1"><a class="header-anchor" href="#开启docker远程端口" aria-hidden="true">#</a> 开启docker远程端口</h3><h4 id="修改docker-service" tabindex="-1"><a class="header-anchor" href="#修改docker-service" aria-hidden="true">#</a> 修改docker.service</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /lib/systemd/system/docker.service

<span class="token comment"># 找到ExecStart参数并替换为下面代码</span>
<span class="token assign-left variable">ExecStart</span><span class="token operator">=</span>/usr/bin/dockerd <span class="token parameter variable">-H</span> unix:///var/run/docker.sock <span class="token parameter variable">-H</span> tcp://0.0.0.0:2375
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container tip"><p class="custom-container-title">提示</p><p>实际有三种方法可以修改，具体实现方式可自行Google</p></div><div class="custom-container danger"><p class="custom-container-title">风险</p><p><code>ExecStart</code>公开2375端口意味着放开了RemoteApi权限，有病毒注入风险</p></div><h4 id="重启docker服务" tabindex="-1"><a class="header-anchor" href="#重启docker服务" aria-hidden="true">#</a> 重启docker服务</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>systemctl daemon-reload
systemctl restart <span class="token function">docker</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="远程连接" tabindex="-1"><a class="header-anchor" href="#远程连接" aria-hidden="true">#</a> 远程连接</h3><p>访问portainer，选择左侧菜单<code>environments</code>，然后点击添加环境，<code>Environment type</code>选择<code>Docker</code></p><ul><li><code>Name</code> docker名称，管理列表中展示管理</li><li><code>Environment URL</code> 远程docker地址，端口默认是<code>2375</code></li></ul><div class="custom-container warning"><p class="custom-container-title">备注</p><p><code>portainer</code>不同版本命名有差异，本教程以当前最新版本<code>2.9.2</code>为准</p></div>`,23),d=[c];function i(o,t){return a(),n("div",null,d)}const p=e(r,[["render",i],["__file","docker-install-portainer.html.vue"]]);export{p as default};
